@contextmanager
def traced_query(name, statement, params=None):
    params = params or ()
    with capture_span(
        name=name,
        span_type="db",
        span_subtype="sqlite",
        span_action="query",
        leaf=True,
        labels={"sql.statement": statement, "sql.params": repr(params)},
    ):
        yield


