@app.route("/items", methods=["POST"])
def create_item():
    payload = request.get_json(silent=True) or {}
    name = payload.get("name", "default-item")
    db = get_db()
    statement = "INSERT INTO items (name, created_at) VALUES (?, ?)"
    params = (name, time.time())
    with traced_query("insert_item", statement, params):
        cur = db.execute(statement, params)
        db.commit()
    return jsonify({"id": cur.lastrowid, "name": name}), 201


@app.route("/items", methods=["GET"])
def list_items():
    db = get_db()
    statement = "SELECT id, name, created_at FROM items ORDER BY id DESC"
    with traced_query("list_items", statement):
        rows = db.execute(statement).fetchall()
    return jsonify([dict(row) for row in rows])


